"""Static dashboard app_js asset."""

APP_JS = '(() => {\n"use strict";\nconst d=window.MOMENTUM_DASHBOARD||{};const s=d.summary||{};\nconst $=id=>document.getElementById(id);const arr=v=>Array.isArray(v)?v:[];\nconst txt=v=>v===null||v===undefined||v===""?"—":String(v);\nconst num=(v,f=0)=>{const n=Number(v);return Number.isFinite(n)?n:f};\nconst int=v=>Math.round(num(v));\nconst pct=(v,digits=1)=>Number.isFinite(Number(v))?`${(Number(v)*100).toFixed(digits)}%`:"—";\nconst money=v=>{const n=num(v,NaN);if(!Number.isFinite(n))return"—";if(Math.abs(n)>=1e8)return`${(n/1e8).toFixed(1)}億円`;if(Math.abs(n)>=1e4)return`${Math.round(n/1e4).toLocaleString()}万円`;return`${Math.round(n).toLocaleString()}円`};\nconst price=v=>Number.isFinite(Number(v))?`${Math.round(Number(v)).toLocaleString()}円`:"—";\nconst signed=(v,d=1,suffix="")=>{const n=Number(v);if(!Number.isFinite(n))return"—";return`${n>0?"+":""}${n.toFixed(d)}${suffix}`};\nconst esc=v=>txt(v).replace(/[&<>\\\'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\\\'":"&#39;",\'"\':"&quot;"}[c]));\nconst bool=v=>v===true||String(v).toLowerCase()==="true"||v===1;\nconst summary=(key,fallback="—")=>s[key]??fallback;\nfunction tag(text){return text&&text!=="—"?`<span class="tag">${esc(text)}</span>`:""}\nfunction statusClass(value){return String(value).toUpperCase()==="PASS"?"pass":"warn"}\nfunction researchBucket(row){return row.research_bucket||row.action_priority||"—"}\nfunction marketGuidance(regime){return regime==="過熱警戒"?"上昇は強い一方、飛びつきを避け、乖離と出来高減速を確認。":regime==="強気"?"重点候補と継続銘柄を優先し、流動性を確認しながら深掘り。":regime==="やや強気"?"初動・加速候補のうち複数条件が重なる銘柄を選別。":regime==="弱気"?"新規候補を絞り、流動性と下振れリスクを優先。":"単独シグナルではなく複数条件が重なる候補を優先。"}\nfunction initNav(){const b=$("navToggle"),n=$("siteNav");if(!b||!n)return;b.addEventListener("click",()=>n.classList.toggle("open"));n.querySelectorAll("a").forEach(a=>a.addEventListener("click",()=>n.classList.remove("open")))}\nfunction renderOverview(){const regime=summary("Market Regime","判定待ち"),score=int(summary("Market Regime Score",0));$("reportDate").textContent=`レポート ${summary("実行日")}`;$("priceDate").textContent=`株価日 ${summary("株価データ日")}`;const fresh=$("freshBadge");fresh.textContent=`運用 ${summary("Run Health","UNKNOWN")}`;fresh.classList.add(statusClass(summary("Run Health")));$("regimeCard").innerHTML=`<div class="eyebrow" style="color:#93c5fd">MARKET REGIME</div><div class="regime-score">${score}</div><div class="regime-label">${esc(regime)}</div><div class="regime-guidance">${esc(marketGuidance(regime))}</div><div class="regime-breadth"><span>20日線上 ${pct(summary("Top100 20日線上比率"))}</span><span>60日線上 ${pct(summary("Top100 60日線上比率"))}</span><span>過熱 ${int(summary("Top100 過熱銘柄数",0))}件</span></div>`;\nconst metrics=[\n["Top100",summary("Momentum Top100",d.top100?.length||0),`新規 ${summary("新規ランクイン",0)}`],\n["年初来高値",summary("年初来高値更新",0),"市場の広がり"],\n["急上昇",summary("急上昇",0),"20位以上上昇"],\n["品質A",summary("Data Quality A",0),`適格率 ${pct(summary("Data Quality A適格率"))}`],\n["相対強度S/A",summary("相対強度S/A",0),`双方超過 ${summary("市場・同業双方超過",0)}`],\n["取得失敗",summary("取得失敗",0),`当日率 ${pct(summary("当日株価比率"))}`]\n];$("summaryMetrics").innerHTML=metrics.map(x=>`<article class="metric-card"><div class="metric-label">${esc(x[0])}</div><div class="metric-value">${esc(x[1])}</div><div class="metric-sub">${esc(x[2])}</div></article>`).join("")}\nfunction renderActions(){const actions=arr(d.actions);const counts={A:0,B:0,C:0,Watch:0,Skip:0};actions.forEach(r=>{const b=researchBucket(r);if(counts[b]!==undefined)counts[b]++});$("actionCounts").innerHTML=Object.entries(counts).map(([k,v])=>`<span class="count-chip ${k.toLowerCase()}">${k} ${v}</span>`).join("");let selected=actions.filter(r=>bool(r.daily_action_list)).sort((a,b)=>num(a.daily_action_rank,999)-num(b.daily_action_rank,999));if(!selected.length)selected=actions.filter(r=>["A","B"].includes(researchBucket(r))).slice(0,5);$("actionCards").innerHTML=selected.length?selected.map((r,i)=>`<article class="action-card bucket-${researchBucket(r).toLowerCase()}"><div class="action-top"><div><div class="action-title">${i+1}. ${esc(r.code)} ${esc(r.name)}</div><div class="tag-row">${tag(r.sector33)}${tag(r.lifecycle_status)}${tag(`品質${r.data_quality_grade||"—"}`)}${tag(`相対${r.relative_strength_grade||"—"}`)}</div></div><div><span class="bucket-badge">${esc(researchBucket(r))}</span><div class="action-score">${num(r.action_score).toFixed(1)}</div></div></div><div class="action-block"><b>今日の理由</b>${esc(r.why_today||r.positive_reasons)}</div><div class="action-block"><b>前回からの変化</b>${esc(r.what_changed||"大きな変化なし")}</div><div class="action-block risk"><b>注意</b>${esc(r.risk_summary||r.caution_reasons||"特記事項なし")}</div><div class="action-block next"><b>次に確認すること</b>${esc(r.next_research_questions||"最新開示、チャート、同業比較を確認")}</div></article>`).join(""):`<div class="empty-state" style="grid-column:1/-1">本日のA/B候補はありません。Watchの改善を待ちます。</div>`}\nlet rankingState={rows:arr(d.top100),selected:null};\nfunction rankBadge(r){const tags=[];if(bool(r.is_new_entry))tags.push("NEW");if(bool(r.is_rising_fast))tags.push("急上昇");if(bool(r.is_best_rank))tags.push("最高順位");if(num(r.top30_streak)>=3)tags.push(`TOP30 ${int(r.top30_streak)}日`);return tags.join(" / ")}\nfunction filteredRanking(){const q=$("searchInput").value.trim().toLowerCase(),sector=$("sectorFilter").value,quality=$("qualityFilter").value,life=$("lifecycleFilter").value,newOnly=$("newOnly").checked,risingOnly=$("risingOnly").checked,sort=$("sortFilter").value;let rows=rankingState.rows.filter(r=>(!q||`${r.code} ${r.name}`.toLowerCase().includes(q))&&(!sector||r.sector33===sector)&&(!quality||r.data_quality_grade===quality)&&(!life||(r.relative_strength_lifecycle||r.lifecycle_status)===life)&&(!newOnly||bool(r.is_new_entry))&&(!risingOnly||bool(r.is_rising_fast)));const sorters={rank:(a,b)=>num(a.rank,999)-num(b.rank,999),score:(a,b)=>num(b.score)-num(a.score),return20:(a,b)=>num(b.return_20d,-999)-num(a.return_20d,-999),volume:(a,b)=>num(b.volume_ratio)-num(a.volume_ratio),relative:(a,b)=>num(b.relative_strength_score)-num(a.relative_strength_score)};return rows.sort(sorters[sort]||sorters.rank)}\nfunction renderRanking(){const rows=filteredRanking();$("rankingCount").textContent=`${rows.length}件`;$("rankingBody").innerHTML=rows.map(r=>`<tr data-code="${esc(r.code)}"><td><b>#${int(r.rank)}</b></td><td><div class="stock-name">${esc(r.name)}</div><div class="stock-code">${esc(r.code)} / ${esc(r.sector33)}</div></td><td>${researchBucket(r)!=="—"?`<span class="count-chip ${researchBucket(r).toLowerCase()}">${esc(researchBucket(r))}</span>`:"—"}</td><td class="score">${int(r.score)}</td><td class="${num(r.return_20d)>=0?"positive":"negative"}">${pct(r.return_20d)}</td><td>${num(r.volume_ratio).toFixed(1)}倍</td><td>${esc(r.relative_strength_grade||"—")} ${num(r.relative_strength_score).toFixed(1)}</td><td><span class="quality ${esc(r.data_quality_grade||"D")}">${esc(r.data_quality_grade||"D")}</span></td><td>${esc(rankBadge(r)||r.relative_strength_lifecycle||"—")}</td></tr>`).join("");$("rankingBody").querySelectorAll("tr").forEach(tr=>tr.addEventListener("click",()=>showStock(tr.dataset.code)))}\nfunction sparkline(values){const clean=values.map(Number).filter(Number.isFinite);if(clean.length<2)return"";const min=Math.min(...clean),max=Math.max(...clean),range=max-min||1,pts=clean.map((v,i)=>`${(i/(clean.length-1))*100},${76-((v-min)/range)*66}`).join(" ");return`<svg class="sparkline" viewBox="0 0 100 84" preserveAspectRatio="none" aria-label="順位履歴"><polyline points="${pts}" fill="none" stroke="#2563eb" stroke-width="2" vector-effect="non-scaling-stroke"/><line x1="0" x2="100" y1="76" y2="76" stroke="#dbe4ef" stroke-width="1"/></svg>`}\nfunction showStock(code){const r=rankingState.rows.find(x=>String(x.code)===String(code));if(!r)return;rankingState.selected=code;const history=(d.ranking_history||{})[String(code)]||[];const ranks=history.map(x=>x.rank).filter(x=>Number.isFinite(Number(x))).map(x=>-Number(x));$("stockDetail").classList.remove("empty-state");$("stockDetail").innerHTML=`<div class="stock-detail-grid"><div><div class="eyebrow">#${int(r.rank)} / ${esc(r.sector33)}</div><h3>${esc(r.code)} ${esc(r.name)}</h3><div class="tag-row">${tag(researchBucket(r))}${tag(r.relative_strength_lifecycle)}${tag(`相対${r.relative_strength_grade||"—"}`)}${tag(`品質${r.data_quality_grade||"—"}`)}${rankBadge(r).split(" / ").map(tag).join("")}</div><div class="action-block"><b>今日の理由</b>${esc(r.why_today||r.reason||"—")}</div><div class="action-block"><b>変化</b>${esc(r.what_changed||rankBadge(r)||"大きな変化なし")}</div><div class="action-block risk"><b>注意</b>${esc(r.risk_summary||r.data_quality_warnings||"特記事項なし")}</div><div class="action-block"><b>次の調査</b>${esc(r.next_research_questions||"最新開示・チャート・同業比較を確認")}</div></div><div><div class="detail-kpis"><div class="mini-kpi"><span>終値</span><b>${price(r.close)}</b></div><div class="mini-kpi"><span>Momentum</span><b>${int(r.score)}点</b></div><div class="mini-kpi"><span>20日</span><b>${pct(r.return_20d)}</b></div><div class="mini-kpi"><span>出来高</span><b>${num(r.volume_ratio).toFixed(1)}倍</b></div><div class="mini-kpi"><span>相対強度</span><b>${num(r.relative_strength_score).toFixed(1)}</b></div><div class="mini-kpi"><span>売買代金</span><b>${money(r.trading_value)}</b></div></div><div class="bar-meta" style="margin-top:14px">直近${history.length}回の順位推移（上方向ほど高順位）</div>${sparkline(ranks)}</div></div>`;$("stockDetail").scrollIntoView({behavior:"smooth",block:"nearest"})}\nfunction initFilters(){const sectors=[...new Set(rankingState.rows.map(r=>r.sector33).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"ja"));$("sectorFilter").insertAdjacentHTML("beforeend",sectors.map(v=>`<option>${esc(v)}</option>`).join(""));const lives=[...new Set(rankingState.rows.map(r=>r.relative_strength_lifecycle||r.lifecycle_status).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"ja"));$("lifecycleFilter").insertAdjacentHTML("beforeend",lives.map(v=>`<option>${esc(v)}</option>`).join(""));["searchInput","sectorFilter","qualityFilter","lifecycleFilter","sortFilter","newOnly","risingOnly"].forEach(id=>$(id).addEventListener(id==="searchInput"?"input":"change",renderRanking));$("resetFilters").addEventListener("click",()=>{["searchInput","sectorFilter","qualityFilter","lifecycleFilter"].forEach(id=>$(id).value="");$("sortFilter").value="rank";$("newOnly").checked=false;$("risingOnly").checked=false;renderRanking()})}\nlet activeChange="新規";function renderChanges(){const rows=arr(d.priority_changes).filter(r=>r.status===activeChange);$("changeList").innerHTML=rows.length?rows.map(r=>`<article class="list-card"><div class="list-card-title">${esc(r.code)} ${esc(r.name)}</div><div class="list-card-sub">${r.status==="脱落"?`前回 #${int(r.previous_rank)} → ${r.current_rank?`現在 #${int(r.current_rank)}`:"Top100圏外"}`:`#${int(r.current_rank)} / ${int(r.current_score)}点`} ・ ${esc(r.priority_lifecycle_status||"")}</div><div class="list-card-reason">${esc(r.status==="脱落"?(r.exit_reason||"重点条件外"):(r.current_labels||"—"))}<br>20日 ${pct(r.return_20d)} ・ 出来高 ${num(r.volume_ratio).toFixed(1)}倍</div></article>`).join(""):\'<div class="empty-state" style="grid-column:1/-1">該当なし</div>\'}\nfunction initChanges(){$("changeTabs").querySelectorAll("button").forEach(b=>b.addEventListener("click",()=>{$("changeTabs").querySelectorAll("button").forEach(x=>x.classList.remove("active"));b.classList.add("active");activeChange=b.dataset.change;renderChanges()}))}\nfunction renderSectors(){const sectors=arr(d.sectors);$("sectorList").innerHTML=sectors.map(r=>`<div class="bar-row"><div class="bar-head"><span>#${int(r.sector_rank)} ${esc(r.sector33)}</span><span>${num(r.sector_momentum_score).toFixed(1)}点 / ${esc(r.sector_strength)}</span></div><div class="bar-track"><div class="bar-fill" style="width:${Math.max(0,Math.min(100,num(r.sector_momentum_score)))}%"></div></div><div class="bar-meta">Top100 ${int(r.top100_count)}/${int(r.stock_count)} ・ 平均20日 ${pct(r.avg_return_20d)} ・ 20日線上 ${pct(r.above_ma20_ratio)} ・ ${esc(r.sector_rotation||"履歴開始")}</div></div>`).join("");$("leaderList").innerHTML=arr(d.sector_leaders).slice(0,15).map(r=>`<div class="compact-row"><div class="compact-title">#${int(r.overall_leader_rank)} ${esc(r.code)} ${esc(r.name)} <span style="float:right">${num(r.sector_leader_score).toFixed(1)}点</span></div><div class="compact-meta">${esc(r.sector33)} / ${esc(r.sector_research_priority)} ・ Momentum #${int(r.momentum_rank)} ・ 相対 ${esc(r.relative_strength_grade)} ・ 20日 ${pct(r.return_20d)}</div></div>`).join("")}\nfunction renderRelative(){const rows=arr(d.relative_strength).slice(0,18);const lifecycle=new Map(arr(d.relative_strength_lifecycle).map(r=>[String(r.code),r]));$("relativeCards").innerHTML=rows.map(r=>{const l=lifecycle.get(String(r.code))||{};return`<article class="list-card"><div class="list-card-title">#${int(r.relative_strength_rank)} ${esc(r.code)} ${esc(r.name)} <span style="float:right;color:#15803d">${num(r.relative_strength_score).toFixed(1)} ${esc(r.relative_strength_grade)}</span></div><div class="list-card-sub">Momentum #${int(r.rank)} / ${esc(r.sector33)} ・ ${esc(l.relative_strength_lifecycle||"観察")}</div><div class="list-card-reason">市場20日 ${signed(num(r.market_relative_20d)*100,1,"pt")} ・ 同業20日 ${signed(num(r.sector_relative_20d)*100,1,"pt")}<br>${esc(l.relative_strength_lifecycle_reason||r.relative_strength_reason||"")}</div></article>`}).join("")}\nfunction renderQuality(){const rows=rankingState.rows,counts={A:0,B:0,C:0,D:0};rows.forEach(r=>counts[r.data_quality_grade||"D"]=(counts[r.data_quality_grade||"D"]||0)+1);$("qualityCounts").innerHTML=Object.entries(counts).map(([k,v])=>`<span class="count-chip ${k.toLowerCase()}">${k} ${v}</span>`).join("");const warns=rows.filter(r=>(r.data_quality_grade||"D")!=="A"||r.data_quality_warnings||r.data_quality_reason_codes);$("qualityWarnings").innerHTML=warns.length?warns.map(r=>`<article class="warning-item"><strong><span class="quality ${esc(r.data_quality_grade||"D")}">${esc(r.data_quality_grade||"D")}</span> #${int(r.rank)} ${esc(r.code)} ${esc(r.name)}</strong><p>${esc(r.data_quality_warnings||r.data_quality_reason_codes||"品質確認が必要")}</p></article>`).join(""):\'<div class="empty-state" style="grid-column:1/-1">品質警告はありません。</div>\'}\nfunction renderResearch(){const perf=arr(d.paper_performance)[0]||{};$("paperSummary").innerHTML=`<div class="paper-kpis"><div><span>資産</span><b>${money(perf.equity)}</b></div><div><span>投資比率</span><b>${pct(perf.exposure_ratio)}</b></div><div><span>DD</span><b>${pct(perf.drawdown)}</b></div></div>`;$("paperPositions").innerHTML=arr(d.paper_portfolio).map(r=>`<div class="compact-row"><div class="compact-title">${esc(r.status)} ${esc(r.code)} ${esc(r.name)} <span style="float:right">${price(r.current_price)}</span></div><div class="compact-meta">${int(r.quantity).toLocaleString()}株 ・ Entry ${price(r.entry_price)} ・ Stop ${price(r.stop_price)} ・ Target ${price(r.target_price)} ・ 損益 ${money(r.unrealized_pnl)}</div></div>`).join("")||\'<div class="empty-state">保有なし</div>\';$("signalPerformance").innerHTML=arr(d.signal_performance).filter(r=>r.group==="全重点候補").map(r=>`<div class="compact-row"><div class="compact-title">${int(r.horizon)}日後 <span style="float:right">${int(r.count)}件</span></div><div class="compact-meta">勝率 ${pct(r.win_rate)} ・ 平均 ${pct(r.average_return)} ・ 中央値 ${pct(r.median_return)}</div></div>`).join("");$("evidenceList").innerHTML=arr(d.research_evidence).map(r=>`<div class="compact-row"><div class="compact-title">${esc(r.label||r.study_id)} <span style="float:right">${esc(r.status)}</span></div><div class="compact-meta">${esc(r.decision||r.evidence_class)}${r.weight_points!==null&&r.weight_points!==undefined?` ・ 配点 ${int(r.weight_points)}点`:""}<br>${esc(r.interpretation||"")}</div></div>`).join("");const health=arr(d.run_health),alerts=arr(d.operational_alerts);$("operationsList").innerHTML=[...health.slice(0,12).map(r=>`<div class="compact-row"><div class="compact-title">${esc(r.check_name)} <span style="float:right;color:${r.status==="PASS"?"#15803d":"#b45309"}">${esc(r.status)}</span></div><div class="compact-meta">${esc(r.detail||r.actual)}</div></div>`),...alerts.filter(r=>["P0","P1"].includes(r.severity)).map(r=>`<div class="compact-row"><div class="compact-title">${esc(r.severity)} ${esc(r.title)}</div><div class="compact-meta">${esc(r.action)}</div></div>`)].join("")}\nfunction init(){initNav();renderOverview();renderActions();initFilters();renderRanking();initChanges();renderChanges();renderSectors();renderRelative();renderQuality();renderResearch();$("footerVersion").textContent=`${d.site_version||""} / ${String(d.payload_sha256||"").slice(0,12)}`}\ndocument.addEventListener("DOMContentLoaded",init);\n})();'
